SELECT AVG(maturity_days) AS average_maturity_days, variety
FROM crops
GROUP BY variety;

SELECT trait_id, trait_name, trait_description
FROM traits
ORDER BY trait_id ASC;

SELECT top_yield_group, years_in_test
FROM yield_comparison
WHERE location = 'Iowa' AND years_in_test > 1;

SELECT trait_name, trait_description, COUNT(*) AS trait_count
FROM traits
GROUP BY trait_name, trait_description;
